import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

export default function CommunityAdminMembers() {
  const [community, setCommunity] = useState(null);
  const [members, setMembers] = useState([]);
  const [joinRequests, setJoinRequests] = useState([]);
  const [tab, setTab] = useState('requests');
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const communityRes = await api.get('/communities/my/profile');
      const c = communityRes.data.data;
      setCommunity(c);
      const [membersRes, requestsRes] = await Promise.all([
        api.get(`/communities/${c._id}/members`),
        api.get(`/communities/${c._id}/join-requests`),
      ]);
      setMembers(membersRes.data.data || []);
      setJoinRequests(requestsRes.data.data || []);
    } catch { toast.error('Failed to load data'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleRequest = async (requestId, action, userName) => {
    try {
      const endpoint = `/communities/${community._id}/join-requests/${requestId}/${action}`;
      await api.put(endpoint, action === 'reject' ? { reason: prompt('Rejection reason (optional):') || '' } : {});
      toast.success(`${userName}'s request ${action}ed`);
      fetchData();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const removeMember = async (userId, name) => {
    if (!window.confirm(`Remove ${name} from this community?`)) return;
    try {
      await api.delete(`/communities/${community._id}/members/${userId}`);
      toast.success(`${name} removed`);
      fetchData();
    } catch { toast.error('Failed to remove member'); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>
                MEMBER <span className="gradient-text">MANAGEMENT</span>
              </h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>{community?.name}</p>
            </div>
            <Link to="/community-admin" className="btn btn-outline">← Dashboard</Link>
          </div>
        </div>

        {/* Tabs */}
        <div className="tabs">
          <button className={`tab-btn ${tab === 'requests' ? 'active' : ''}`} onClick={() => setTab('requests')}>
            Pending Requests {joinRequests.length > 0 && <span style={{ background: 'var(--warning)', color: 'black', borderRadius: 100, padding: '1px 7px', fontSize: '0.65rem', marginLeft: 6 }}>{joinRequests.length}</span>}
          </button>
          <button className={`tab-btn ${tab === 'members' ? 'active' : ''}`} onClick={() => setTab('members')}>
            Current Members ({members.length})
          </button>
        </div>

        {/* Pending Requests */}
        {tab === 'requests' && (
          <>
            {joinRequests.length === 0 ? (
              <div className="empty-state"><div className="empty-state-icon">✅</div><div>No pending requests</div></div>
            ) : (
              <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                {joinRequests.map(req => (
                  <div key={req._id} className="card">
                    <div style={{ display: 'flex', alignItems: 'center', gap: 14 }}>
                      <div className="avatar avatar-lg">{req.user?.name?.charAt(0)}</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 700, fontSize: '0.95rem', marginBottom: 2 }}>{req.user?.name}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{req.user?.email}</div>
                        {req.user?.itNumber && (
                          <div style={{ fontSize: '0.75rem', fontFamily: 'var(--font-mono)', color: 'var(--cyan-accent)', marginTop: 2 }}>{req.user.itNumber}</div>
                        )}
                      </div>
                      <div style={{ textAlign: 'right' }}>
                        <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: 10 }}>
                          {new Date(req.createdAt).toLocaleDateString()}
                        </div>
                        <div style={{ display: 'flex', gap: 8 }}>
                          <button onClick={() => handleRequest(req._id, 'approve', req.user?.name)} className="btn btn-success btn-sm">✓ Approve</button>
                          <button onClick={() => handleRequest(req._id, 'reject', req.user?.name)} className="btn btn-danger btn-sm">✗ Reject</button>
                        </div>
                      </div>
                    </div>
                    {req.message && (
                      <div style={{ marginTop: 12, padding: '10px 14px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)', fontSize: '0.82rem', color: 'var(--text-secondary)', fontStyle: 'italic' }}>
                        "{req.message}"
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* Current Members */}
        {tab === 'members' && (
          <>
            {members.length === 0 ? (
              <div className="empty-state"><div className="empty-state-icon">👥</div><div>No members yet</div></div>
            ) : (
              <div className="table-wrapper">
                <table>
                  <thead>
                    <tr>
                      <th>MEMBER</th>
                      <th>IT NUMBER</th>
                      <th>ROLE</th>
                      <th>JOINED</th>
                      <th>ACTIONS</th>
                    </tr>
                  </thead>
                  <tbody>
                    {members.map(m => (
                      <tr key={m._id || m.user?._id}>
                        <td>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                            <div className="avatar">{m.user?.name?.charAt(0)}</div>
                            <div>
                              <div style={{ fontWeight: 600, fontSize: '0.875rem' }}>{m.user?.name}</div>
                              <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{m.user?.email}</div>
                            </div>
                          </div>
                        </td>
                        <td><span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', color: 'var(--cyan-accent)' }}>{m.user?.itNumber || '—'}</span></td>
                        <td><span className="badge badge-student">{m.role || 'member'}</span></td>
                        <td style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>{m.joinedAt ? new Date(m.joinedAt).toLocaleDateString() : '—'}</td>
                        <td>
                          <button onClick={() => removeMember(m.user?._id, m.user?.name)} className="btn btn-sm btn-outline" style={{ borderColor: 'var(--danger)', color: 'var(--danger)' }}>
                            Remove
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
